package com.example.debug.server;

import java.lang.management.ManagementFactory;
import java.lang.management.ThreadInfo;
import java.lang.management.ThreadMXBean;
import java.net.InetAddress;
import java.util.HashMap;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.atomic.AtomicLong;

public class InternalStateTracker {

    private final AtomicLong requestCount = new AtomicLong(0);
    private final AtomicLong errorCount = new AtomicLong(0);
    private final ConcurrentHashMap<String, String> activeRequests = new ConcurrentHashMap<>();
    private final ConcurrentHashMap<String, Object> internalCache = new ConcurrentHashMap<>();

    public void trackRequest(String requestId, String details) {
        requestCount.incrementAndGet();
        activeRequests.put(requestId, details);
    }

    public void trackError(String requestId) {
        errorCount.incrementAndGet();
    }

    public void completeRequest(String requestId) {
        activeRequests.remove(requestId);
    }

    public void cacheData(String key, Object value) {
        internalCache.put(key, value);
    }

    // INSECURE: Exposes full internal state
    public String getFullInternalState() {
        StringBuilder state = new StringBuilder();
        state.append("=== INTERNAL SERVER STATE ===\n");
        state.append("Total Requests: ").append(requestCount.get()).append("\n");
        state.append("Total Errors: ").append(errorCount.get()).append("\n");
        state.append("Active Requests: ").append(activeRequests.toString()).append("\n");
        state.append("Cache Contents: ").append(internalCache.toString()).append("\n");
        state.append("Available Processors: ").append(Runtime.getRuntime().availableProcessors()).append("\n");
        state.append("Free Memory: ").append(Runtime.getRuntime().freeMemory()).append("\n");
        state.append("Total Memory: ").append(Runtime.getRuntime().totalMemory()).append("\n");
        state.append("Max Memory: ").append(Runtime.getRuntime().maxMemory()).append("\n");
        return state.toString();
    }

    // INSECURE: Exposes server hostname and IP
    public String getServerHostname() {
        try {
            return InetAddress.getLocalHost().getHostName();
        } catch (Exception e) {
            return "unknown";
        }
    }

    public String getServerIp() {
        try {
            return InetAddress.getLocalHost().getHostAddress();
        } catch (Exception e) {
            return "unknown";
        }
    }

    // INSECURE: Exposes all environment variables
    public Map<String, String> getEnvironmentVariables() {
        return new HashMap<>(System.getenv());
    }

    // INSECURE: Exposes all system properties
    public Map<String, String> getSystemProperties() {
        Map<String, String> props = new HashMap<>();
        System.getProperties().forEach((k, v) -> props.put(k.toString(), v.toString()));
        return props;
    }

    // INSECURE: Exposes full thread dump
    public String getThreadDump() {
        StringBuilder dump = new StringBuilder();
        ThreadMXBean threadMXBean = ManagementFactory.getThreadMXBean();
        ThreadInfo[] threadInfos = threadMXBean.dumpAllThreads(true, true);
        for (ThreadInfo info : threadInfos) {
            dump.append(info.toString());
        }
        return dump.toString();
    }
}

