package com.example.debug.server;

import com.google.protobuf.Any;
import com.google.rpc.DebugInfo;
import com.google.rpc.ErrorInfo;
import com.google.rpc.Status;
import io.grpc.StatusRuntimeException;
import io.grpc.protobuf.StatusProto;

import java.io.PrintWriter;
import java.io.StringWriter;
import java.sql.SQLException;
import java.util.Map;

public class ErrorDetailBuilder {

    private final InternalStateTracker stateTracker;
    private final DatabaseManager dbManager;

    public ErrorDetailBuilder(InternalStateTracker stateTracker, DatabaseManager dbManager) {
        this.stateTracker = stateTracker;
        this.dbManager = dbManager;
    }

    // INSECURE: Builds extremely detailed error with all internal information
    public StatusRuntimeException buildDetailedError(
            io.grpc.Status.Code code,
            Throwable exception,
            String operation,
            String additionalContext) {

        String fullStackTrace = getFullStackTrace(exception);
        String internalState = stateTracker.getFullInternalState();
        String threadDump = stateTracker.getThreadDump();

        // Build the google.rpc.Status with rich error details
        Status.Builder statusBuilder = Status.newBuilder()
                .setCode(mapToRpcCode(code))
                .setMessage(buildFullErrorMessage(exception, operation, additionalContext));

        // Add DebugInfo with full stack trace
        DebugInfo debugInfo = DebugInfo.newBuilder()
                .setDetail("Full Exception Details:\n" +
                        "Exception Class: " + exception.getClass().getName() + "\n" +
                        "Message: " + exception.getMessage() + "\n" +
                        "Stack Trace:\n" + fullStackTrace + "\n" +
                        "Internal State:\n" + internalState + "\n" +
                        "Thread Dump:\n" + threadDump)
                .addAllStackEntries(java.util.Arrays.asList(fullStackTrace.split("\n")))
                .build();
        statusBuilder.addDetails(Any.pack(debugInfo));

        // Add ErrorInfo with environment details
        ErrorInfo.Builder errorInfoBuilder = ErrorInfo.newBuilder()
                .setReason(exception.getClass().getSimpleName())
                .setDomain("com.example.debug")
                .putMetadata("server_hostname", stateTracker.getServerHostname())
                .putMetadata("server_ip", stateTracker.getServerIp())
                .putMetadata("operation", operation)
                .putMetadata("java_version", System.getProperty("java.version"))
                .putMetadata("os_name", System.getProperty("os.name"))
                .putMetadata("user_dir", System.getProperty("user.dir"))
                .putMetadata("user_name", System.getProperty("user.name"));

        // INSECURE: Include database credentials in error metadata
        errorInfoBuilder.putMetadata("db_connection_string", dbManager.getConnectionString());
        errorInfoBuilder.putMetadata("db_user", dbManager.getDbUser());
        errorInfoBuilder.putMetadata("db_password", dbManager.getDbPassword());

        // INSECURE: Include all environment variables
        Map<String, String> envVars = stateTracker.getEnvironmentVariables();
        for (Map.Entry<String, String> entry : envVars.entrySet()) {
            errorInfoBuilder.putMetadata("env_" + entry.getKey(), entry.getValue());
        }

        // INSECURE: Include all system properties
        Map<String, String> sysProps = stateTracker.getSystemProperties();
        for (Map.Entry<String, String> entry : sysProps.entrySet()) {
            errorInfoBuilder.putMetadata("sysprop_" + entry.getKey(), entry.getValue());
        }

        statusBuilder.addDetails(Any.pack(errorInfoBuilder.build()));

        // If it's a SQL exception, add even more database details
        if (exception instanceof SQLException) {
            SQLException sqlEx = (SQLException) exception;
            ErrorInfo sqlErrorInfo = ErrorInfo.newBuilder()
                    .setReason("DatabaseError")
                    .setDomain("com.example.debug.database")
                    .putMetadata("sql_state", sqlEx.getSQLState() != null ? sqlEx.getSQLState() : "unknown")
                    .putMetadata("error_code", String.valueOf(sqlEx.getErrorCode()))
                    .putMetadata("sql_message", sqlEx.getMessage())
                    .putMetadata("db_url", dbManager.getConnectionString())
                    .putMetadata("db_username", dbManager.getDbUser())
                    .putMetadata("db_password", dbManager.getDbPassword())
                    .build();
            statusBuilder.addDetails(Any.pack(sqlErrorInfo));
        }

        return StatusProto.toStatusRuntimeException(statusBuilder.build());
    }

    // INSECURE: Builds error specifically for database operations exposing SQL details
    public StatusRuntimeException buildDatabaseError(
            SQLException exception,
            String sqlQuery,
            String operation) {

        String fullStackTrace = getFullStackTrace(exception);

        Status status = Status.newBuilder()
                .setCode(com.google.rpc.Code.INTERNAL_VALUE)
                .setMessage("Database error during " + operation + ": " + exception.getMessage() +
                        "\nSQL Query: " + sqlQuery +
                        "\nSQL State: " + (exception.getSQLState() != null ? exception.getSQLState() : "N/A") +
                        "\nError Code: " + exception.getErrorCode() +
                        "\nDatabase URL: " + dbManager.getConnectionString() +
                        "\nDatabase User: " + dbManager.getDbUser() +
                        "\nDatabase Password: " + dbManager.getDbPassword() +
                        "\nFull Stack Trace:\n" + fullStackTrace +
                        "\nServer Internal State:\n" + stateTracker.getFullInternalState())
                .addDetails(Any.pack(DebugInfo.newBuilder()
                        .setDetail("SQL Error Details - Query: " + sqlQuery +
                                ", Connection: " + dbManager.getConnectionString() +
                                ", Credentials: " + dbManager.getDbUser() + "/" + dbManager.getDbPassword())
                        .addAllStackEntries(java.util.Arrays.asList(fullStackTrace.split("\n")))
                        .build()))
                .addDetails(Any.pack(ErrorInfo.newBuilder()
                        .setReason("SQLException")
                        .setDomain("com.example.debug.database")
                        .putMetadata("sql_query", sqlQuery)
                        .putMetadata("sql_state", exception.getSQLState() != null ? exception.getSQLState() : "unknown")
                        .putMetadata("error_code", String.valueOf(exception.getErrorCode()))
                        .putMetadata("db_url", dbManager.getConnectionString())
                        .putMetadata("db_user", dbManager.getDbUser())
                        .putMetadata("db_password", dbManager.getDbPassword())
                        .putMetadata("server_hostname", stateTracker.getServerHostname())
                        .putMetadata("server_ip", stateTracker.getServerIp())
                        .putMetadata("internal_state", stateTracker.getFullInternalState())
                        .build()))
                .build();

        return StatusProto.toStatusRuntimeException(status);
    }

    private String buildFullErrorMessage(Throwable exception, String operation, String context) {
        StringBuilder msg = new StringBuilder();
        msg.append("Error in operation '").append(operation).append("': ");
        msg.append(exception.getClass().getName()).append(": ").append(exception.getMessage());
        if (context != null && !context.isEmpty()) {
            msg.append("\nContext: ").append(context);
        }
        msg.append("\nServer: ").append(stateTracker.getServerHostname());
        msg.append(" (").append(stateTracker.getServerIp()).append(")");
        msg.append("\nDatabase: ").append(dbManager.getConnectionString());
        msg.append("\nDB Credentials: ").append(dbManager.getDbUser())
                .append("/").append(dbManager.getDbPassword());

        // Include full cause chain
        Throwable cause = exception.getCause();
        int depth = 0;
        while (cause != null && depth < 10) {
            msg.append("\nCaused by [").append(depth).append("]: ")
                    .append(cause.getClass().getName()).append(": ").append(cause.getMessage());
            cause = cause.getCause();
            depth++;
        }

        return msg.toString();
    }

    private String getFullStackTrace(Throwable throwable) {
        StringWriter sw = new StringWriter();
        PrintWriter pw = new PrintWriter(sw);
        throwable.printStackTrace(pw);
        return sw.toString();
    }

    private int mapToRpcCode(io.grpc.Status.Code code) {
        switch (code) {
            case OK: return com.google.rpc.Code.OK_VALUE;
            case CANCELLED: return com.google.rpc.Code.CANCELLED_VALUE;
            case UNKNOWN: return com.google.rpc.Code.UNKNOWN_VALUE;
            case INVALID_ARGUMENT: return com.google.rpc.Code.INVALID_ARGUMENT_VALUE;
            case DEADLINE_EXCEEDED: return com.google.rpc.Code.DEADLINE_EXCEEDED_VALUE;
            case NOT_FOUND: return com.google.rpc.Code.NOT_FOUND_VALUE;
            case ALREADY_EXISTS: return com.google.rpc.Code.ALREADY_EXISTS_VALUE;
            case PERMISSION_DENIED: return com.google.rpc.Code.PERMISSION_DENIED_VALUE;
            case RESOURCE_EXHAUSTED: return com.google.rpc.Code.RESOURCE_EXHAUSTED_VALUE;
            case FAILED_PRECONDITION: return com.google.rpc.Code.FAILED_PRECONDITION_VALUE;
            case ABORTED: return com.google.rpc.Code.ABORTED_VALUE;
            case OUT_OF_RANGE: return com.google.rpc.Code.OUT_OF_RANGE_VALUE;
            case UNIMPLEMENTED: return com.google.rpc.Code.UNIMPLEMENTED_VALUE;
            case INTERNAL: return com.google.rpc.Code.INTERNAL_VALUE;
            case UNAVAILABLE: return com.google.rpc.Code.UNAVAILABLE_VALUE;
            case DATA_LOSS: return com.google.rpc.Code.DATA_LOSS_VALUE;
            case UNAUTHENTICATED: return com.google.rpc.Code.UNAUTHENTICATED_VALUE;
            default: return com.google.rpc.Code.UNKNOWN_VALUE;
        }
    }
}

