package com.example.debug.server;

import com.example.debug.grpc.*;
import io.grpc.Status;
import io.grpc.stub.StreamObserver;

import java.sql.SQLException;
import java.util.List;
import java.util.UUID;

public class DebugServiceImpl extends DebugServiceGrpc.DebugServiceImplBase {

    private final DatabaseManager dbManager;
    private final InternalStateTracker stateTracker;
    private final ErrorDetailBuilder errorDetailBuilder;

    public DebugServiceImpl(DatabaseManager dbManager, InternalStateTracker stateTracker) {
        this.dbManager = dbManager;
        this.stateTracker = stateTracker;
        this.errorDetailBuilder = new ErrorDetailBuilder(stateTracker, dbManager);
    }

    @Override
    public void getUser(GetUserRequest request, StreamObserver<GetUserResponse> responseObserver) {
        String requestId = UUID.randomUUID().toString();
        stateTracker.trackRequest(requestId, "GetUser: " + request.getUserId());

        try {
            if (request.getUserId() == null || request.getUserId().isEmpty()) {
                throw new IllegalArgumentException(
                        "User ID cannot be null or empty. Received: '" + request.getUserId() + "'" +
                                " from request: " + request.toString());
            }

            DatabaseManager.UserRecord user = dbManager.getUser(request.getUserId());

            if (user == null) {
                // INSECURE: Exposes database query details and internal state in NOT_FOUND error
                stateTracker.trackError(requestId);
                throw new RuntimeException(
                        "User not found with ID: " + request.getUserId() +
                                ". Searched in database: " + dbManager.getConnectionString() +
                                " using credentials: " + dbManager.getDbUser() + "/" + dbManager.getDbPassword() +
                                ". Table: users. Query: SELECT * FROM users WHERE user_id = '" +
                                request.getUserId() + "'");
            }

            // INSECURE: Cache sensitive user data in internal state
            stateTracker.cacheData("last_user_lookup", user.toString());

            GetUserResponse response = GetUserResponse.newBuilder()
                    .setUserId(user.userId)
                    .setName(user.name)
                    .setEmail(user.email)
                    .build();

            responseObserver.onNext(response);
            responseObserver.onCompleted();

        } catch (SQLException e) {
            stateTracker.trackError(requestId);
            // INSECURE: Full database error details exposed
            responseObserver.onError(
                    errorDetailBuilder.buildDatabaseError(
                            e,
                            "SELECT * FROM users WHERE user_id = '" + request.getUserId() + "'",
                            "GetUser"));

        } catch (IllegalArgumentException e) {
            stateTracker.trackError(requestId);
            responseObserver.onError(
                    errorDetailBuilder.buildDetailedError(
                            Status.Code.INVALID_ARGUMENT,
                            e,
                            "GetUser",
                            "Request validation failed for user_id: " + request.getUserId()));

        } catch (Exception e) {
            stateTracker.trackError(requestId);
            // INSECURE: Full exception details including stack trace and internal state
            responseObserver.onError(
                    errorDetailBuilder.buildDetailedError(
                            Status.Code.NOT_FOUND,
                            e,
                            "GetUser",
                            "Full request: " + request.toString() +
                                    ", Internal cache state: " + stateTracker.getFullInternalState()));
        } finally {
            stateTracker.completeRequest(requestId);
        }
    }

    @Override
    public void updateUser(UpdateUserRequest request, StreamObserver<UpdateUserResponse> responseObserver) {
        String requestId = UUID.randomUUID().toString();
        stateTracker.trackRequest(requestId, "UpdateUser: " + request.toString());

        try {
            if (request.getUserId() == null || request.getUserId().isEmpty()) {
                throw new IllegalArgumentException("User ID is required for update. Full request: " + request);
            }

            dbManager.updateUser(request.getUserId(), request.getName(), request.getEmail());

            stateTracker.cacheData("last_update", "Updated user " + request.getUserId() +
                    " with name=" + request.getName() + ", email=" + request.getEmail());

            UpdateUserResponse response = UpdateUserResponse.newBuilder()
                    .setSuccess(true)
                    .build();

            responseObserver.onNext(response);
            responseObserver.onCompleted();

        } catch (SQLException e) {
            stateTracker.trackError(requestId);
            // INSECURE: Exposes the UPDATE SQL query and database credentials
            responseObserver.onError(
                    errorDetailBuilder.buildDatabaseError(
                            e,
                            "UPDATE users SET name = '" + request.getName() +
                                    "', email = '" + request.getEmail() +
                                    "' WHERE user_id = '" + request.getUserId() + "'",
                            "UpdateUser"));

        } catch (Exception e) {
            stateTracker.trackError(requestId);
            responseObserver.onError(
                    errorDetailBuilder.buildDetailedError(
                            Status.Code.INTERNAL,
                            e,
                            "UpdateUser",
                            "Failed to update user. Request: " + request.toString()));
        } finally {
            stateTracker.completeRequest(requestId);
        }
    }

    @Override
    public void deleteUser(DeleteUserRequest request, StreamObserver<DeleteUserResponse> responseObserver) {
        String requestId = UUID.randomUUID().toString();
        stateTracker.trackRequest(requestId, "DeleteUser: " + request.getUserId());

        try {
            if (request.getUserId() == null || request.getUserId().isEmpty()) {
                throw new IllegalArgumentException("User ID required for deletion");
            }

            // First check if user exists (to demonstrate data leakage)
            DatabaseManager.UserRecord existingUser = dbManager.getUser(request.getUserId());
            if (existingUser == null) {
                // INSECURE: Tells attacker the user doesn't exist and leaks DB details
                throw new RuntimeException(
                        "Cannot delete non-existent user: " + request.getUserId() +
                                ". Database: " + dbManager.getConnectionString() +
                                ". Existing users can be found in the 'users' table.");
            }

            dbManager.deleteUser(request.getUserId());

            // INSECURE: Log deleted user's sensitive data in internal state
            stateTracker.cacheData("last_deleted_user", existingUser.toString());

            DeleteUserResponse response = DeleteUserResponse.newBuilder()
                    .setSuccess(true)
                    .build();

            responseObserver.onNext(response);
            responseObserver.onCompleted();

        } catch (SQLException e) {
            stateTracker.trackError(requestId);
            responseObserver.onError(
                    errorDetailBuilder.buildDatabaseError(
                            e,
                            "DELETE FROM users WHERE user_id = '" + request.getUserId() + "'",
                            "DeleteUser"));

        } catch (Exception e) {
            stateTracker.trackError(requestId);
            responseObserver.onError(
                    errorDetailBuilder.buildDetailedError(
                            Status.Code.INTERNAL,
                            e,
                            "DeleteUser",
                            "Delete operation failed. User ID: " + request.getUserId()));
        } finally {
            stateTracker.completeRequest(requestId);
        }
    }

    @Override
    public void queryDatabase(QueryRequest request, StreamObserver<QueryResponse> responseObserver) {
        String requestId = UUID.randomUUID().toString();
        stateTracker.trackRequest(requestId, "QueryDatabase: " + request.getSqlQuery());

        try {
            if (request.getSqlQuery() == null || request.getSqlQuery().isEmpty()) {
                throw new IllegalArgumentException("SQL query cannot be empty");
            }

            // INSECURE: Executes arbitrary SQL queries from client input
            List<String> results = dbManager.executeRawQuery(request.getSqlQuery());

            stateTracker.cacheData("last_query", request.getSqlQuery());
            stateTracker.cacheData("last_query_results", results.toString());

            QueryResponse response = QueryResponse.newBuilder()
                    .addAllResults(results)
                    .build();

            responseObserver.onNext(response);
            responseObserver.onCompleted();

        } catch (SQLException e) {
            stateTracker.trackError(requestId);
            // INSECURE: Returns the exact SQL error, helping attackers craft SQL injection
            responseObserver.onError(
                    errorDetailBuilder.buildDatabaseError(
                            e,
                            request.getSqlQuery(),
                            "QueryDatabase - Raw SQL execution"));

        } catch (Exception e) {
            stateTracker.trackError(requestId);
            responseObserver.onError(
                    errorDetailBuilder.buildDetailedError(
                            Status.Code.INTERNAL,
                            e,
                            "QueryDatabase",
                            "Failed to execute query: " + request.getSqlQuery() +
                                    " on database: " + dbManager.getConnectionString()));
        } finally {
            stateTracker.completeRequest(requestId);
        }
    }
}

