package com.example.debug.server;

import com.google.protobuf.Any;
import com.google.rpc.DebugInfo;
import com.google.rpc.ErrorInfo;
import io.grpc.ForwardingServerCallListener.SimpleForwardingServerCallListener;
import io.grpc.Metadata;
import io.grpc.ServerCall;
import io.grpc.ServerCallHandler;
import io.grpc.ServerInterceptor;
import io.grpc.StatusRuntimeException;
import io.grpc.protobuf.StatusProto;

import java.io.PrintWriter;
import java.io.StringWriter;

public class GlobalExceptionInterceptor implements ServerInterceptor {

    private final InternalStateTracker stateTracker;
    private final DatabaseManager dbManager;

    public GlobalExceptionInterceptor(InternalStateTracker stateTracker, DatabaseManager dbManager) {
        this.stateTracker = stateTracker;
        this.dbManager = dbManager;
    }

    @Override
    public <ReqT, RespT> ServerCall.Listener<ReqT> interceptCall(
            ServerCall<ReqT, RespT> call,
            Metadata headers,
            ServerCallHandler<ReqT, RespT> next) {

        ServerCall.Listener<ReqT> listener = next.startCall(call, headers);

        return new SimpleForwardingServerCallListener<ReqT>(listener) {
            @Override
            public void onHalfClose() {
                try {
                    super.onHalfClose();
                } catch (StatusRuntimeException e) {
                    // Re-throw StatusRuntimeException as-is (already has details)
                    throw e;
                } catch (Exception e) {
                    // INSECURE: Catch-all that exposes everything
                    StringWriter sw = new StringWriter();
                    e.printStackTrace(new PrintWriter(sw));
                    String stackTrace = sw.toString();

                    com.google.rpc.Status status = com.google.rpc.Status.newBuilder()
                            .setCode(com.google.rpc.Code.INTERNAL_VALUE)
                            .setMessage("Unhandled exception in gRPC service: " +
                                    e.getClass().getName() + ": " + e.getMessage() +
                                    "\nServer: " + stateTracker.getServerHostname() +
                                    " (" + stateTracker.getServerIp() + ")" +
                                    "\nDatabase: " + dbManager.getConnectionString() +
                                    "\nDB User: " + dbManager.getDbUser() +
                                    "\nDB Password: " + dbManager.getDbPassword() +
                                    "\nFull Stack Trace:\n" + stackTrace +
                                    "\nInternal State:\n" + stateTracker.getFullInternalState() +
                                    "\nThread Dump:\n" + stateTracker.getThreadDump())
                            .addDetails(Any.pack(DebugInfo.newBuilder()
                                    .setDetail("Unhandled exception caught by global interceptor")
                                    .addAllStackEntries(
                                            java.util.Arrays.asList(stackTrace.split("\n")))
                                    .build()))
                            .addDetails(Any.pack(ErrorInfo.newBuilder()
                                    .setReason("UnhandledException")
                                    .setDomain("com.example.debug.interceptor")
                                    .putMetadata("exception_class", e.getClass().getName())
                                    .putMetadata("exception_message", e.getMessage() != null ? e.getMessage() : "null")
                                    .putMetadata("method", call.getMethodDescriptor().getFullMethodName())
                                    .putMetadata("server_hostname", stateTracker.getServerHostname())
                                    .putMetadata("server_ip", stateTracker.getServerIp())
                                    .putMetadata("db_url", dbManager.getConnectionString())
                                    .putMetadata("db_user", dbManager.getDbUser())
                                    .putMetadata("db_password", dbManager.getDbPassword())
                                    .putMetadata("internal_state", stateTracker.getFullInternalState())
                                    .build()))
                            .build();

                    throw StatusProto.toStatusRuntimeException(status);
                }
            }

            @Override
            public void onMessage(ReqT message) {
                try {
                    super.onMessage(message);
                } catch (Exception e) {
                    StringWriter sw = new StringWriter();
                    e.printStackTrace(new PrintWriter(sw));

                    // INSECURE: Expose message processing errors with full details
                    com.google.rpc.Status status = com.google.rpc.Status.newBuilder()
                            .setCode(com.google.rpc.Code.INTERNAL_VALUE)
                            .setMessage("Error processing message: " + e.getMessage() +
                                    "\nMessage content: " + message.toString() +
                                    "\nStack trace: " + sw.toString())
                            .build();

                    throw StatusProto.toStatusRuntimeException(status);
                }
            }
        };
    }
}

