package com.example.debug.server;

import io.grpc.Server;
import io.grpc.ServerBuilder;

import java.io.IOException;
import java.sql.SQLException;

public class DebugGrpcServer {

    private final int port;
    private Server server;
    private DatabaseManager dbManager;
    private InternalStateTracker stateTracker;

    public DebugGrpcServer(int port) {
        this.port = port;
    }

    public void start() throws IOException, SQLException {
        dbManager = new DatabaseManager();
        stateTracker = new InternalStateTracker();

        // INSECURE: No TLS, no authentication, no authorization
        server = ServerBuilder.forPort(port)
                .addService(new DebugServiceImpl(dbManager, stateTracker))
                .intercept(new GlobalExceptionInterceptor(stateTracker, dbManager))
                // No TLS configured - plaintext communication
                // No authentication interceptor
                // No authorization checks
                .build()
                .start();

        System.out.println("=== INSECURE DEBUG gRPC Server started on port " + port + " ===");
        System.out.println("WARNING: This server exposes detailed error information!");
        System.out.println("Server hostname: " + stateTracker.getServerHostname());
        System.out.println("Server IP: " + stateTracker.getServerIp());
        System.out.println("Database URL: " + dbManager.getConnectionString());
        System.out.println("Database User: " + dbManager.getDbUser());
        System.out.println("Database Password: " + dbManager.getDbPassword());

        Runtime.getRuntime().addShutdownHook(new Thread(() -> {
            System.out.println("Shutting down gRPC server...");
            DebugGrpcServer.this.stop();
        }));
    }

    public void stop() {
        if (server != null) {
            server.shutdown();
        }
    }

    public void blockUntilShutdown() throws InterruptedException {
        if (server != null) {
            server.awaitTermination();
        }
    }

    public static void main(String[] args) throws Exception {
        int port = 50051;
        if (args.length > 0) {
            port = Integer.parseInt(args[0]);
        }

        DebugGrpcServer server = new DebugGrpcServer(port);
        server.start();
        server.blockUntilShutdown();
    }
}

