package com.example.debug.client;

import com.example.debug.grpc.*;
import com.google.protobuf.Any;
import com.google.protobuf.InvalidProtocolBufferException;
import com.google.rpc.DebugInfo;
import com.google.rpc.ErrorInfo;
import io.grpc.ManagedChannel;
import io.grpc.ManagedChannelBuilder;
import io.grpc.StatusRuntimeException;
import io.grpc.protobuf.StatusProto;

import java.util.concurrent.TimeUnit;

public class DebugGrpcClient {

    private final ManagedChannel channel;
    private final DebugServiceGrpc.DebugServiceBlockingStub blockingStub;

    public DebugGrpcClient(String host, int port) {
        // INSECURE: Plaintext channel, no TLS
        channel = ManagedChannelBuilder.forAddress(host, port)
                .usePlaintext()
                .build();
        blockingStub = DebugServiceGrpc.newBlockingStub(channel);
    }

    public void shutdown() throws InterruptedException {
        channel.shutdown().awaitTermination(5, TimeUnit.SECONDS);
    }

    public void getUser(String userId) {
        System.out.println("\n=== GetUser Request: userId=" + userId + " ===");
        try {
            GetUserRequest request = GetUserRequest.newBuilder()
                    .setUserId(userId)
                    .build();
            GetUserResponse response = blockingStub.getUser(request);
            System.out.println("Success: " + response);
        } catch (StatusRuntimeException e) {
            printDetailedError(e);
        }
    }

    public void updateUser(String userId, String name, String email) {
        System.out.println("\n=== UpdateUser Request: userId=" + userId + " ===");
        try {
            UpdateUserRequest request = UpdateUserRequest.newBuilder()
                    .setUserId(userId)
                    .setName(name)
                    .setEmail(email)
                    .build();
            UpdateUserResponse response = blockingStub.updateUser(request);
            System.out.println("Success: " + response.getSuccess());
        } catch (StatusRuntimeException e) {
            printDetailedError(e);
        }
    }

    public void deleteUser(String userId) {
        System.out.println("\n=== DeleteUser Request: userId=" + userId + " ===");
        try {
            DeleteUserRequest request = DeleteUserRequest.newBuilder()
                    .setUserId(userId)
                    .build();
            DeleteUserResponse response = blockingStub.deleteUser(request);
            System.out.println("Success: " + response.getSuccess());
        } catch (StatusRuntimeException e) {
            printDetailedError(e);
        }
    }

    public void queryDatabase(String sql) {
        System.out.println("\n=== QueryDatabase Request: sql=" + sql + " ===");
        try {
            QueryRequest request = QueryRequest.newBuilder()
                    .setSqlQuery(sql)
                    .build();
            QueryResponse response = blockingStub.queryDatabase(request);
            System.out.println("Results:");
            for (String result : response.getResultsList()) {
                System.out.println("  " + result);
            }
        } catch (StatusRuntimeException e) {
            printDetailedError(e);
        }
    }

    private void printDetailedError(StatusRuntimeException e) {
        System.out.println("\n--- ERROR DETAILS ---");
        System.out.println("Status Code: " + e.getStatus().getCode());
        System.out.println("Description: " + e.getStatus().getDescription());

        // Extract rich error details from the status
        com.google.rpc.Status rpcStatus = StatusProto.fromThrowable(e);
        if (rpcStatus != null) {
            System.out.println("RPC Status Code: " + rpcStatus.getCode());
            System.out.println("RPC Message: " + rpcStatus.getMessage());

            for (Any detail : rpcStatus.getDetailsList()) {
                try {
                    if (detail.is(DebugInfo.class)) {
                        DebugInfo debugInfo = detail.unpack(DebugInfo.class);
                        System.out.println("\n[DebugInfo]");
                        System.out.println("Detail: " + debugInfo.getDetail());
                        System.out.println("Stack Entries (" + debugInfo.getStackEntriesCount() + "):");
                        for (String entry : debugInfo.getStackEntriesList()) {
                            System.out.println("  " + entry);
                        }
                    } else if (detail.is(ErrorInfo.class)) {
                        ErrorInfo errorInfo = detail.unpack(ErrorInfo.class);
                        System.out.println("\n[ErrorInfo]");
                        System.out.println("Reason: " + errorInfo.getReason());
                        System.out.println("Domain: " + errorInfo.getDomain());
                        System.out.println("Metadata:");
                        errorInfo.getMetadataMap().forEach((k, v) ->
                                System.out.println("  " + k + " = " + v));
                    }
                } catch (InvalidProtocolBufferException ex) {
                    System.out.println("Failed to unpack detail: " + ex.getMessage());
                }
            }
        }
        System.out.println("--- END ERROR DETAILS ---\n");
    }

    public static void main(String[] args) throws Exception {
        String host = "localhost";
        int port = 50051;

        DebugGrpcClient client = new DebugGrpcClient(host, port);

        try {
            // Test 1: Get existing user
            client.getUser("user1");

            // Test 2: Get non-existent user (triggers detailed error)
            client.getUser("nonexistent_user");

            // Test 3: Get user with empty ID (triggers validation error)
            client.getUser("");

            // Test 4: Update non-existent user (triggers database error)
            client.updateUser("nonexistent", "Test", "test@test.com");

            // Test 5: Delete non-existent user
            client.deleteUser("nonexistent_user");

            // Test 6: Execute valid SQL query (exposes all user data including sensitive fields)
            client.queryDatabase("SELECT * FROM users");

            // Test 7: Execute invalid SQL (triggers SQL error with full details)
            client.queryDatabase("SELECT * FROM nonexistent_table");

            // Test 8: SQL injection attempt (server will return helpful error details)
            client.queryDatabase("SELECT * FROM users; DROP TABLE users; --");

        } finally {
            client.shutdown();
        }
    }
}

