package com.example.debug.secure;

import com.example.debug.grpc.*;
import com.example.debug.server.DatabaseManager;
import io.grpc.Status;
import io.grpc.stub.StreamObserver;

import java.sql.SQLException;
import java.util.UUID;
import java.util.logging.Level;
import java.util.logging.Logger;

/**
 * SECURE alternative implementation showing how errors SHOULD be handled.
 * This is provided as a contrast to the insecure DebugServiceImpl.
 */
public class SecureDebugServiceImpl extends DebugServiceGrpc.DebugServiceImplBase {

    private static final Logger logger = Logger.getLogger(SecureDebugServiceImpl.class.getName());
    private final DatabaseManager dbManager;

    public SecureDebugServiceImpl(DatabaseManager dbManager) {
        this.dbManager = dbManager;
    }

    @Override
    public void getUser(GetUserRequest request, StreamObserver<GetUserResponse> responseObserver) {
        String correlationId = UUID.randomUUID().toString();

        try {
            if (request.getUserId() == null || request.getUserId().isEmpty()) {
                responseObserver.onError(
                        Status.INVALID_ARGUMENT
                                .withDescription("User ID is required")
                                .asRuntimeException());
                return;
            }

            DatabaseManager.UserRecord user = dbManager.getUser(request.getUserId());

            if (user == null) {
                responseObserver.onError(
                        Status.NOT_FOUND
                                .withDescription("User not found")
                                .asRuntimeException());
                return;
            }

            // Only return non-sensitive fields
            GetUserResponse response = GetUserResponse.newBuilder()
                    .setUserId(user.userId)
                    .setName(user.name)
                    .setEmail(user.email)
                    .build();

            responseObserver.onNext(response);
            responseObserver.onCompleted();

        } catch (SQLException e) {
            // Log full details server-side only
            logger.log(Level.SEVERE, "Database error [correlationId=" + correlationId + "]", e);

            // Return generic error to client with correlation ID for support
            responseObserver.onError(
                    Status.INTERNAL
                            .withDescription("An internal error occurred. Reference: " + correlationId)
                            .asRuntimeException());

        } catch (Exception e) {
            logger.log(Level.SEVERE, "Unexpected error [correlationId=" + correlationId + "]", e);

            responseObserver.onError(
                    Status.INTERNAL
                            .withDescription("An unexpected error occurred. Reference: " + correlationId)
                            .asRuntimeException());
        }
    }
}